logger = logging.getLogger(__name__)


class RabbitMQConfig:
    """Configuration for RabbitMQ connection with authentication."""

    def __init__(
        self,
        host: str = 'localhost',
        port: int = 5672,
        username: str = 'taskuser',
        password: str = 'taskpassword',
        virtual_host: str = '/',
        heartbeat: int = 600,
        blocked_connection_timeout: int = 300,
        connection_attempts: int = 3,
        retry_delay: int = 5,
        ssl_enabled: bool = False
    ):
        if not username or not password:
            raise ValueError("Authentication credentials (username and password) are required. Anonymous connections are not allowed.")

        if len(password) < 8:
            raise ValueError("Password must be at least 8 characters long for security.")

        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.virtual_host = virtual_host
        self.heartbeat = heartbeat
        self.blocked_connection_timeout = blocked_connection_timeout
        self.connection_attempts = connection_attempts
        self.retry_delay = retry_delay
        self.ssl_enabled = ssl_enabled

    def get_connection_parameters(self) -> pika.ConnectionParameters:
        """Build pika ConnectionParameters with authentication."""
        credentials = pika.PlainCredentials(
            username=self.username,
            password=self.password
        )

        ssl_options = None
        if self.ssl_enabled:
            import ssl
            context = ssl.create_default_context()
            ssl_options = pika.SSLOptions(context, self.host)

        parameters = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            heartbeat=self.heartbeat,
            blocked_connection_timeout=self.blocked_connection_timeout,
            connection_attempts=self.connection_attempts,
            retry_delay=self.retry_delay,
            ssl_options=ssl_options
        )

        return parameters


class RabbitMQConnection:
    """Manages RabbitMQ connection lifecycle."""

    def __init__(self, config: RabbitMQConfig):
        self.config = config
        self._connection: Optional[pika.BlockingConnection] = None
        self._channel: Optional[pika.channel.Channel] = None

    def connect(self) -> pika.channel.Channel:
        """Establish connection and return a channel."""
        if self._connection and self._connection.is_open:
            if self._channel and self._channel.is_open:
                return self._channel

        logger.info(f"Connecting to RabbitMQ at {self.config.host}:{self.config.port} as user '{self.config.username}'")

        parameters = self.config.get_connection_parameters()
        self._connection = pika.BlockingConnection(parameters)
        self._channel = self._connection.channel()

        logger.info("Successfully connected to RabbitMQ")
        return self._channel

    def close(self):
        """Close connection gracefully."""
        try:
            if self._channel and self._channel.is_open:
                self._channel.close()
            if self._connection and self._connection.is_open:
                self._connection.close()
            logger.info("RabbitMQ connection closed")
        except Exception as e:
            logger.error(f"Error closing connection: {e}")

    @property
    def channel(self) -> pika.channel.Channel:
        if not self._channel or not self._channel.is_open:
            return self.connect()
        return self._channel

    def __enter__(self):
        self.connect()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()


class TaskPublisher:
    """Publishes task messages to RabbitMQ queues."""

    TASK_QUEUE = 'task_queue'
    TASK_EXCHANGE = 'task_exchange'
    DEAD_LETTER_EXCHANGE = 'dlx_exchange'
    DEAD_LETTER_QUEUE = 'dead_letter_queue'
    RESULT_QUEUE = 'result_queue'

    def __init__(self, config: RabbitMQConfig):
        self.config = config
        self.connection_manager = RabbitMQConnection(config)

    def setup_infrastructure(self):
        """Declare exchanges, queues, and bindings."""
        channel = self.connection_manager.connect()

        # Dead letter exchange and queue
        channel.exchange_declare(
            exchange=self.DEAD_LETTER_EXCHANGE,
            exchange_type='direct',
            durable=True
        )
        channel.queue_declare(
            queue=self.DEAD_LETTER_QUEUE,
            durable=True
        )
        channel.queue_bind(
            queue=self.DEAD_LETTER_QUEUE,
            exchange=self.DEAD_LETTER_EXCHANGE,
            routing_key='dead_letter'
        )

        # Task exchange
        channel.exchange_declare(
            exchange=self.TASK_EXCHANGE,
            exchange_type='direct',
            durable=True
        )

        # Task queue with dead letter configuration
        channel.queue_declare(
            queue=self.TASK_QUEUE,
            durable=True,
            arguments={
                'x-dead-letter-exchange': self.DEAD_LETTER_EXCHANGE,
                'x-dead-letter-routing-key': 'dead_letter',
                'x-message-ttl': 3600000,  # 1 hour TTL
                'x-max-length': 10000
            }
        )
        channel.queue_bind(
            queue=self.TASK_QUEUE,
            exchange=self.TASK_EXCHANGE,
            routing_key='task'
        )

        # Result queue
        channel.queue_declare(
            queue=self.RESULT_QUEUE,
            durable=True
        )

        # Enable publisher confirms
        channel.confirm_delivery()

        logger.info("RabbitMQ infrastructure setup complete")

    def publish_task(
        self,
        task_type: str,
        payload: dict,
        priority: int = 0,
        correlation_id: Optional[str] = None
    ) -> str:
        """Publish a task message to the task queue."""
        task_id = correlation_id or str(uuid.uuid4())

        message = {
            'task_id': task_id,
            'task_type': task_type,
            'payload': payload,
            'created_at': datetime.utcnow().isoformat(),
            'retry_count': 0,
            'max_retries': 3
        }

        properties = pika.BasicProperties(
            delivery_mode=2,  # Persistent
            content_type='application/json',
            correlation_id=task_id,
            priority=priority,
            timestamp=int(time.time()),
            headers={
                'task_type': task_type,
                'version': '1.0'
            }
        )

        channel = self.connection_manager.channel

        try:
            channel.basic_publish(
                exchange=self.TASK_EXCHANGE,
                routing_key='task',
                body=json.dumps(message),
                properties=properties,
                mandatory=True
            )
            logger.info(f"Published task {task_id} of type '{task_type}'")
            return task_id
        except pika.exceptions.UnroutableError:
            logger.error(f"Message {task_id} was returned as unroutable")
            raise
        except pika.exceptions.NackError:
            logger.error(f"Message {task_id} was nacked by broker")
            raise

    def publish_batch(self, tasks: list) -> list:
        """Publish multiple tasks."""
        task_ids = []
        for task in tasks:
            task_id = self.publish_task(
                task_type=task['task_type'],
                payload=task['payload'],
                priority=task.get('priority', 0)
            )
            task_ids.append(task_id)
        return task_ids

    def close(self):
        self.connection_manager.close()


class TaskConsumer:
    """Consumes and processes task messages from RabbitMQ."""

    TASK_QUEUE = 'task_queue'
    TASK_EXCHANGE = 'task_exchange'
    DEAD_LETTER_EXCHANGE = 'dlx_exchange'
    DEAD_LETTER_QUEUE = 'dead_letter_queue'
    RESULT_QUEUE = 'result_queue'

    def __init__(self, config: RabbitMQConfig, prefetch_count: int = 1):
        self.config = config
        self.prefetch_count = prefetch_count
        self.connection_manager = RabbitMQConnection(config)
        self._task_handlers: dict[str, Callable] = {}
        self._running = False

    def register_handler(self, task_type: str, handler: Callable):
        """Register a handler function for a specific task type."""
        self._task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type '{task_type}'")

    def _on_message(self, channel, method, properties, body):
        """Callback for processing received messages."""
        task_id = properties.correlation_id or 'unknown'

        try:
            message = json.loads(body)
            task_type = message.get('task_type', 'unknown')
            payload = message.get('payload', {})
            retry_count = message.get('retry_count', 0)
            max_retries = message.get('max_retries', 3)

            logger.info(f"Received task {task_id} of type '{task_type}' (attempt {retry_count + 1})")

            handler = self._task_handlers.get(task_type)
            if not handler:
                logger.warning(f"No handler registered for task type '{task_type}'")
                # Reject and don't requeue - send to dead letter
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Process the task
            result = handler(task_id, payload)

            # Publish result
            self._publish_result(channel, task_id, task_type, result)

            # Acknowledge successful processing
            channel.basic_ack(delivery_tag=method.delivery_tag)
            logger.info(f"Task {task_id} processed successfully")

        except json.JSONDecodeError as e:
            logger.error(f"Invalid JSON in message: {e}")
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

        except Exception as e:
            logger.error(f"Error processing task {task_id}: {e}")

            try:
                message = json.loads(body)
                retry_count = message.get('retry_count', 0)
                max_retries = message.get('max_retries', 3)

                if retry_count < max_retries:
                    # Retry: republish with incremented retry count
                    message['retry_count'] = retry_count + 1
                    message['last_error'] = str(e)
                    message['last_retry_at'] = datetime.utcnow().isoformat()

                    retry_properties = pika.BasicProperties(
                        delivery_mode=2,
                        content_type='application/json',
                        correlation_id=task_id,
                        headers={
                            'task_type': message.get('task_type', 'unknown'),
                            'retry_count': message['retry_count'],
                            'version': '1.0'
                        }
                    )

                    channel.basic_publish(
                        exchange=self.TASK_EXCHANGE,
                        routing_key='task',
                        body=json.dumps(message),
                        properties=retry_properties
                    )
                    logger.info(f"Task {task_id} requeued for retry ({retry_count + 1}/{max_retries})")
                    channel.basic_ack(delivery_tag=method.delivery_tag)
                else:
                    logger.error(f"Task {task_id} exceeded max retries, sending to dead letter queue")
                    channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            except Exception:
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    def _publish_result(self, channel, task_id: str, task_type: str, result: dict):
        """Publish task result to the result queue."""
        result_message = {
            'task_id': task_id,
            'task_type': task_type,
            'result': result,
            'completed_at': datetime.utcnow().isoformat(),
            'status': 'completed'
        }

        properties = pika.BasicProperties(
            delivery_mode=2,
            content_type='application/json',
            correlation_id=task_id
        )

        channel.basic_publish(
            exchange='',
            routing_key=self.RESULT_QUEUE,
            body=json.dumps(result_message),
            properties=properties
        )

    def start_consuming(self):
        """Start consuming messages from the task queue."""
        channel = self.connection_manager.connect()

        # Set QoS - process one message at a time
        channel.basic_qos(prefetch_count=self.prefetch_count)

        channel.basic_consume(
            queue=self.TASK_QUEUE,
            on_message_callback=self._on_message,
            auto_ack=False  # Manual acknowledgment
        )

        self._running = True
        logger.info(f"Consumer started. Waiting for tasks on '{self.TASK_QUEUE}'...")

        try:
            channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
            channel.stop_consuming()
        finally:
            self._running = False
            self.connection_manager.close()

    def stop(self):
        """Stop consuming messages."""
        self._running = False
        if self.connection_manager._channel and self.connection_manager._channel.is_open:
            self.connection_manager._channel.stop_consuming()


